INSERT INTO TB_ALIMXX(
            USER_NUMB
          , ALIM_NUMB
          , ALIM_SITU
          , TEMP_CODE
          , ALIM_TITL
          , ALIM_CONT
          , LINK_URLX
          , READ_YSNO
          , SEND_DATE
          , DELT_YSNO
) VALUES(   #{userNumb}
          , (
                SELECT NVL(MAX(ALIM_NUMB), 0) + 1
                  FROM TB_ALIMXX
                 WHERE USER_NUMB = #{userNumb}
            )
          , #{alimSitu}
          , #{tempCode}
          , #{alimTitl}
          , #{alimCont}
          , #{linkUrlx}
          , #{readYsno}
          , SYSDATE
          , #{deltYsno}
)

mapper.select:

SELECT /* dupSameAlimInHour */
       COUNT(*)
  FROM TB_ALIMXX
 WHERE USER_NUMB = #{userNumb}
   AND ALIM_SITU = #{alimSitu}
   AND TEMP_CODE = #{tempCode}
   AND NVL(ALIM_TITL, ' ') = NVL(#{alimTitl}, ' ')
   AND NVL(ALIM_CONT, ' ') = NVL(#{alimCont}, ' ')
   AND NVL(LINK_URLX, ' ') = NVL(#{linkUrlx}, ' ')
   AND NVL(DELT_YSNO, #{commNo}) = #{commNo}
   AND SEND_DATE >= SYSDATE - (1 / 24)

mapper.update:


